mapper.select:


    AND grid_code LIKE '%' || #{gridCode} || '%'
    AND city = #{city}
    AND province = #{province}
    AND district = #{district}

ORDER BY grid_code

mapper.update:
UPDATE jw_grid_meta
SET longitude = CASE grid_code

    WHEN #{item.gridCode} THEN #{item.longitude}

END,
latitude = CASE grid_code

    WHEN #{item.gridCode} THEN #{item.latitude}

END,
west_longitude = CASE grid_code

    WHEN #{item.gridCode} THEN #{item.westLongitude}

END,
east_longitude = CASE grid_code

    WHEN #{item.gridCode} THEN #{item.eastLongitude}

END,
north_latitude = CASE grid_code

    WHEN #{item.gridCode} THEN #{item.northLatitude}

END,
south_latitude = CASE grid_code

    WHEN #{item.gridCode} THEN #{item.southLatitude}

END,
update_time = now()
WHERE grid_code IN (

    #{item.gridCode}

)

mapper.select:

WHERE west_longitude <= #{longitude}
  AND east_longitude >= #{longitude}
  AND south_latitude <= #{latitude}
  AND north_latitude >= #{latitude}
LIMIT 1
